import json, os, re, shutil, traceback
from datetime import datetime
DATA_FILE = _data_file
BASE_DIR = _base_dir
SNAP_DIR = os.path.join(BASE_DIR,"zhongqu_snapshots")
MEMO_FIELDS = ["功能名称","原始需求","设计思路","注意事项","后续优化"]
SYSTEM_KEYS = ["1","2","3","4","5","6","7","8","9"]

def _load():
    with open(DATA_FILE,encoding="utf-8") as f: return json.load(f)
def _save(d):
    tmp=DATA_FILE+".tmp"
    with open(tmp,"w",encoding="utf-8") as f: json.dump(d,f,ensure_ascii=False,indent=2)
    os.replace(tmp,DATA_FILE)
def _snap():
    os.makedirs(SNAP_DIR,exist_ok=True)
    ts=datetime.now().strftime("%Y%m%d_%H%M%S")
    if os.path.exists(DATA_FILE): shutil.copy2(DATA_FILE,os.path.join(SNAP_DIR,f"snapshot_{ts}.json"))
def _parse_memo(code):
    m=re.search(r'#\s*@AI_MEMO_START(.*?)#\s*@AI_MEMO_END',code,re.DOTALL)
    if not m: return None
    memo={}
    for line in m.group(1).splitlines():
        line=line.strip().lstrip("#").strip()
        for f in MEMO_FIELDS:
            if line.startswith(f+"：") or line.startswith(f+":"):
                memo[f]=line.split("：",1)[-1].split(":",1)[-1].strip()
    return memo if memo else None

data=_load()
all_items=list(data["actions"].items())
sys_fns=[(k,v) for k,v in all_items if k in SYSTEM_KEYS]
tool_fns=[(k,v) for k,v in all_items if k not in SYSTEM_KEYS]

print("\n选择要修改的功能：")
print("  ── 系统功能 ──")
for k,v in sys_fns:
    print(f"  {k}. {v['name']}")
print("  ── 工具功能 ──")
if not tool_fns:
    print("  （暂无工具功能）")
else:
    for i,(k,v) in enumerate(tool_fns,1):
        print(f"  t{i}. {v['name']}")

choice=input("\n编号（系统功能输数字，工具功能输t+数字）：").strip()

key=None
if choice in SYSTEM_KEYS:
    key=choice
elif choice.startswith("t"):
    try:
        key=tool_fns[int(choice[1:])-1][0]
    except (ValueError,IndexError): pass

if not key:
    print("⚠️  无效编号。"); input("回车继续..."); exit()

name=data["actions"][key]["name"]
if key in SYSTEM_KEYS:
    print(f"\n⚠️  你正在修改系统功能「{name}」，请确保代码正确。")

print(f"\n粘贴新代码，输入 END 结束：")
lines=[]
while True:
    line=input()
    if line.strip()=="END": break
    lines.append(line)
code="\n".join(lines)

if not code.strip():
    print("⚠️  没有代码。"); input("回车继续...")
else:
    memo=_parse_memo(code)
    if not memo:
        print("❌ 缺少备忘录，无法保存。"); input("回车继续...")
    else:
        _snap()
        old=data["actions"][key]
        hist=old.get("history",[])
        hist.append({"time":datetime.now().strftime("%Y-%m-%d %H:%M"),"code":old["code"],"memo":old.get("memo",{})})
        try:
            data["actions"][key]={"name":name,"code":code,"memo":memo,"desc":memo.get("原始需求",""),"added":old.get("added",""),"modified":datetime.now().strftime("%Y-%m-%d %H:%M"),"history":hist[-10:]}
            data["log"].append(f"{datetime.now().strftime('%m-%d %H:%M')} 修改「{name}」")
            _save(data)
            print(f"\n✅ 「{name}」已更新。")
        except Exception as e:
            print(f"❌ 出错：{e}\n{traceback.format_exc()}")
        input("\n回车继续...")

