# @AI_MEMO_START
# 功能名称：中枢云同步
# 原始需求：用Gitee私有仓库备份zhongqu_data.json，支持推送/拉取，首次运行配置token存本地，换手机能恢复
# 设计思路：用git命令行操作，token存~/.zhongqu_git.conf，每次推送自动commit带时间戳，拉取前做本地快照
# 注意事项：token只存本地不进json；仓库地址固定为xwin7p/zhongqu-backup；分支是master
# 后续优化：可加自动推送
# @AI_MEMO_END

import os, json, shutil, subprocess
from datetime import datetime

try:
    base = os.path.dirname(_data_file)
    json_src = _data_file
except NameError:
    base = os.path.expanduser("~")
    json_src = os.path.join(base, "zhongqu_data.json")

CONF_FILE = os.path.join(os.path.expanduser("~"), ".zhongqu_git.conf")
SNAP_DIR = os.path.join(base, "zhongqu_snapshots")
REPO_DIR = os.path.join(os.path.expanduser("~"), "zhongqu_backup_repo")
REPO_NAME = "xwin7p/zhongqu-backup"

def load_conf():
    if os.path.exists(CONF_FILE):
        with open(CONF_FILE, encoding="utf-8") as f:
            return json.load(f)
    return None

def save_conf(conf):
    with open(CONF_FILE, "w", encoding="utf-8") as f:
        json.dump(conf, f, ensure_ascii=False, indent=2)
    os.chmod(CONF_FILE, 0o600)

def run(cmd, cwd=None):
    r = subprocess.run(cmd, shell=True, capture_output=True, text=True, cwd=cwd)
    return r.returncode, r.stdout.strip(), r.stderr.strip()

conf = load_conf()
if not conf:
    print("⚙️  首次配置，token只存本地，永不上传\n")
    token = input("Gitee 私人令牌：").strip()
    conf = {"token": token, "repo": REPO_NAME, "host": "gitee.com"}
    save_conf(conf)
    print("✅ 配置已保存到本地\n")

TOKEN = conf["token"]
HOST = conf.get("host", "gitee.com")
REPO_URL = f"https://{TOKEN}@{HOST}/{conf['repo']}.git"

def ensure_repo():
    if not os.path.exists(REPO_DIR):
        print("   首次使用，正在克隆仓库...")
        code, out, err = run(f"git clone {REPO_URL} {REPO_DIR}")
        if code != 0:
            print(f"❌ 克隆失败：{err}")
            return False
        print("   ✅ 克隆成功")
    return True

def push():
    print("\n📤 推送本地 → Gitee...")
    if not ensure_repo():
        return
    try:
        shutil.copy2(json_src, os.path.join(REPO_DIR, "zhongqu_data.json"))
        ts = datetime.now().strftime("%Y-%m-%d %H:%M")
        run("git add zhongqu_data.json", cwd=REPO_DIR)
        code, out, err = run(f'git commit -m "backup {ts}"', cwd=REPO_DIR)
        if "nothing to commit" in out or "nothing to commit" in err:
            print("✅ 云端已是最新，无需推送")
            return
        code, out, err = run(f"git push {REPO_URL} master", cwd=REPO_DIR)
        if code == 0:
            print(f"✅ 推送成功（{ts}）")
        else:
            print(f"❌ 推送失败：{err}")
    except Exception as e:
        print(f"❌ 错误：{e}")

def pull():
    print("\n📥 拉取Gitee → 本地...")
    confirm = input("⚠️  会覆盖本地文件，确认？(y/n)：").strip()
    if confirm != "y":
        print("已取消")
        return
    if not ensure_repo():
        return
    try:
        code, out, err = run("git pull", cwd=REPO_DIR)
        if code != 0:
            print(f"❌ 拉取失败：{err}")
            return
        remote_file = os.path.join(REPO_DIR, "zhongqu_data.json")
        if not os.path.exists(remote_file):
            print("❌ 云端还没有备份，请先推送一次")
            return
        os.makedirs(SNAP_DIR, exist_ok=True)
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(json_src, os.path.join(SNAP_DIR, f"snapshot_{ts}.json"))
        shutil.copy2(remote_file, json_src)
        print("✅ 拉取成功，本地已更新")
    except Exception as e:
        print(f"❌ 错误：{e}")

def check():
    print("\n🔍 检查云端状态...")
    if not ensure_repo():
        return
    try:
        run("git fetch", cwd=REPO_DIR)
        code, out, err = run("git log --oneline -5", cwd=REPO_DIR)
        if code == 0 and out:
            print("✅ 云端最近5次提交：")
            for line in out.split("\n"):
                print(f"   {line}")
        else:
            print("📭 云端暂无提交记录")
    except Exception as e:
        print(f"❌ 错误：{e}")

print("=" * 35)
print("  中枢云同步 · Gitee")
print("=" * 35)
print(f"  仓库：{conf['repo']}")
print("-" * 35)
print("  1. 推送  本地→Gitee（备份）")
print("  2. 拉取  Gitee→本地（恢复）")
print("  3. 检查  云端提交记录")
print("  4. 重新配置token")
print("-" * 35)

choice = input("选择：").strip()
if choice == "1":
    push()
elif choice == "2":
    pull()
elif choice == "3":
    check()
elif choice == "4":
    os.remove(CONF_FILE)
    if os.path.exists(REPO_DIR):
        shutil.rmtree(REPO_DIR)
    print("✅ 配置已清除，下次运行重新填写")
else:
    print("无效选择")

input("\n回车返回...")

