        print(f"❌ 错误：{e}")

def pull():
    print("\n📥 拉取Gitee → 本地...")
    confirm = input("⚠️  会覆盖本地文件，确认？(y/n)：").strip()
    if confirm != "y":
        print("已取消")
        return
    if not ensure_repo():
        return
    try:
        code, out, err = run("git pull", cwd=REPO_DIR)
        if code != 0:
            print(f"❌ 拉取失败：{err}")
            return
        remote_file = os.path.join(REPO_DIR, "zhongqu_data.json")
        if not os.path.exists(remote_file):
            print("❌ 云端还没有备份，请先推送一次")
            return
        os.makedirs(SNAP_DIR, exist_ok=True)
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(json_src, os.path.join(SNAP_DIR, f"snapshot_{ts}.json"))
        shutil.copy2(remote_file, json_src)
        print("✅ 拉取成功，本地已更新")
    except Exception as e:
        print(f"❌ 错误：{e}")

def check():
    print("\n🔍 检查云端状态...")
    if not ensure_repo():
        return
    try:
        run("git fetch", cwd=REPO_DIR)
        code, out, err = run("git log --oneline -5", cwd=REPO_DIR)
        if code == 0 and out:
            print("✅ 云端最近5次提交：")
            for line in out.split("\n"):
                print(f"   {line}")
        else:
            print("📭 云端暂无提交记录")
    except Exception as e:
        print(f"❌ 错误：{e}")

